{"interfaces":["File: src/modules/system/system-metrics.service.ts
export interface SystemHealth {
  nodeVersion: string;
  uptimeSeconds: number;
  memoryUsageMB: number;
}

export class SystemMetricsService {
  getSystemHealth(): SystemHealth {
    const nodeVersion = process.version;
    const uptimeSeconds = process.uptime();
    const memoryUsageMB = process.memoryUsage().heapUsed / (1024 * 1024);

    return {
      nodeVersion,
      uptimeSeconds,
      memoryUsageMB
    };
  }
}"],"importStatements":[],"successCriteria":["src/modules/system/system-metrics.service.ts exists and exports SystemHealth interface and SystemMetricsService class","src/modules/system/index.ts exists and exports SystemHealth interface and SystemMetricsService class","SystemMetricsService.getSystemHealth() returns SystemHealth object with correct node version from process.version","SystemMetricsService.getSystemHealth() returns SystemHealth object with correct uptime in seconds from process.uptime()","SystemMetricsService.getSystemHealth() returns SystemHealth object with correct memory usage in MB calculated from process.memoryUsage().heapUsed / (1024 * 1024)"]}

